class Plh(BaseModel):
    """Player handicap updates."""

    hcaps: Annotated[
        list[PlayerHandicap], Field(description="Handicap list by player.")
    ]
    reqi: Annotated[
        int, Field(description="Request identifier echoed by replies.", ge=0, le=255)
    ]
    type: Literal["Plh"] = "Plh"


class Ipb(BaseModel):
    """IP ban list (host only)."""

    banips: list[IPv4Address]
    reqi: Annotated[
        int, Field(description="Request identifier echoed by replies.", ge=0, le=255)
    ]
    type: Literal["Ipb"] = "Ipb"


class Aic(BaseModel):
    """AI input control packet."""

    inputs: Annotated[
        list[AiInput],
        Field(
            description="Inputs to send (use [AiInput] helpers to build common inputs)."
        ),
    ]
    plid: Annotated[int, Field(description="Player id to control.", ge=0, le=255)]
    reqi: Annotated[
        int, Field(description="Request identifier echoed by replies.", ge=0, le=255)
    ]
    type: Literal["Aic"] = "Aic"


class Aii(BaseModel):
    """AI telemetry snapshot."""

    flags: Annotated[AiFlags, Field(description="AI state flags.")]
    gear: Annotated[int, Field(description="Current gear.", ge=0, le=255)]
    osmain: Annotated[OsMain, Field(description="Outsim-style physical state.")]
    plid: Annotated[int, Field(description="Player id of the AI car.", ge=0, le=255)]
    reqi: Annotated[
        int, Field(description="Request identifier echoed by replies.", ge=0, le=255)
    ]
    rpm: Annotated[float, Field(description="Engine RPM.")]
    showlights: Annotated[DashLights, Field(description="Current dash lights.")]
    type: Literal["Aii"] = "Aii"


class Set(BaseModel):
    """Player sent setup to host"""

    cname: Annotated[str, Field(description="vehicle")]
    fuelload: Annotated[int, Field(description="Fuel Load at start", ge=0, le=255)]
    plid: Annotated[int, Field(description="Player that left the race.", ge=0, le=255)]
    reqi: Annotated[
        int, Field(description="Request identifier echoed by replies.", ge=0, le=255)
    ]
    setup: Annotated[
        list[int],
        Field(
            description="Raw setup bytes. Same format as SET file, with the following exceptions:\n- less the first 12 bytes\n- gear order is the first 7 gears then final drive ratio"
        ),
    ]
    type: Literal["Set"] = "Set"


